import re
import ssl
import certifi
import socket
import ipaddress


def is_safe_url(url: str) -> bool:
    """
    Validate that the URL is safe to fetch.
    - Only allows http and https schemes
    - Prevents access to private/internal IP addresses
    - Prevents access to localhost
    """
    try:
        parsed = urlparse(url)

        # Only allow http and https schemes
        if parsed.scheme not in ['http', 'https']:
            return False

        # Check if hostname is present
        if not parsed.hostname:
            return False

        # Resolve hostname to IP address and check if it's private/internal
        try:
            ip_addresses = socket.getaddrinfo(parsed.hostname, None)
            for family, socktype, proto, canonname, sockaddr in ip_addresses:
                ip = sockaddr[0]
                try:
                    ip_obj = ipaddress.ip_address(ip)
                    # Check if IP is private, loopback, link-local, or reserved
                    if ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_link_local or ip_obj.is_reserved:
                        return False
                except ValueError:
                    # Skip invalid IP addresses
                    continue
        except socket.gaierror:
            # DNS resolution failed
            return False

        return True
    except Exception:
        return False


class SafeRedirectHandler(urllib.request.HTTPRedirectHandler):
    """
    Custom redirect handler that validates redirect URLs to prevent SSRF.
    """
    def redirect_request(self, req, fp, code, msg, headers, newurl):
        # Validate the redirect URL before following it
        if not is_safe_url(newurl):
            raise urllib.error.URLError("Unsafe redirect URL detected")
        return super().redirect_request(req, fp, code, msg, headers, newurl)

    def http_error_302(self, req, fp, code, msg, headers):
        # Validate redirect URL for 302
        newurl = headers.get('Location')
        if newurl and not is_safe_url(newurl):
            raise urllib.error.URLError("Unsafe redirect URL detected")
        return super().http_error_302(req, fp, code, msg, headers)

    def http_error_301(self, req, fp, code, msg, headers):
        # Validate redirect URL for 301
        newurl = headers.get('Location')
        if newurl and not is_safe_url(newurl):
